INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$53654d9e-4c32-4974-82e2-d08d35caef58$tag$, $tag$2026022300044$tag$, $tag$Simone Dilda Rovani (5549999295355)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página de Psicopedagogia e quero mais informações.","time":"23/02/2026 08:58:07"},{"role":"client","text":"🌟 Bom dia Simone Dilda Rovani! Que alegria ter você aqui com a gente! 🙌","time":"23/02/2026 08:58:08"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"23/02/2026 08:58:12"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"23/02/2026 08:58:15"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"23/02/2026 08:58:22"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"23/02/2026 08:58:42"},{"role":"client","text":"Olá! Simone Dilda Rovani!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"23/02/2026 08:58:43"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"23/02/2026 08:58:47"},{"role":"client","text":"Saber sobre os cursos","time":"23/02/2026 08:59:03"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"23/02/2026 08:59:08"},{"role":"client","text":"Pós-Graduação","time":"23/02/2026 08:59:23"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"23/02/2026 08:59:27"},{"role":"client","text":"Psicopedagogia","time":"23/02/2026 09:28:59"},{"role":"client","text":"Essa pós é ideal para quem deseja compreender e intervir nos processos de aprendizagem com uma abordagem ética, cristã e prática.\n\n 🧠 100% online, estude no seu ritmo\n 🎓 Professores experientes e materiais atualizados\n 📅 Aulas iniciam em agosto\n 💰 Condição promocional especial para novas matrículas","time":"23/02/2026 09:29:00"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"23/02/2026 09:29:03"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"23/02/2026 09:30:29"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"23/02/2026 09:30:30"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"23/02/2026 09:42:42"},{"role":"agent","text":"*Karina Pimentel:* * PÓS-GRADUAÇÃO EM PSICOPEDAGOGIA *\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 18 meses.\n\nCARGA HORÁRIA\n630 horas\n\nDISCIPLINAS\n12 disciplinas obrigatórias e 1  disciplina optativa\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n***********************\n*Disciplinas da Pós em Psicopedagogia*\n\nBASE: FILOSÓFICA TEOLÓGICA\n\n1-Introdução à Cosmovisão Cristã - Dr. Bruno Ribeiro\n2-Fundamentos Filosóficos e Metodológicos de uma Pedagogia Cristã - Me. Thiago Dutra\n3-Introdução à Educação Cristã Clássica - Me. Thiago Dutra\n\nBASE: PSICOPEDAGOGIA E DESENVOLVIMENTO\n\n4-Fundamentos da Psicopedagogia - Ma. Luciana Siqueira\n5-Alfabetização Fônica - Esp. Finlândia de Oliveira das Chagas\n6-Aprendizagem da Matemática - Esp. Úrsula Keyla\n7-Desenvolvimento Cognitivo e Neurociência - Alessandra Schneider\n8-Síndromes, Transtornos e Dificuldades de Aprendizagem - Ma. Fabiana Josefa Sousa\n\nBASE: Avaliação, Diagnóstico e Mediação Psicopedagógica\n\n9-Teoria da Experiência de Aprendizagem Mediada em Feuerstein - Me. David Sasson/ Marcia Macionk\n10-Avaliação e Intervenção Psicopedagógica - Dra. Edith Rubstein\n11-Âmbitos de atuação do Psicopedagogo e Educação Formal - Esp. Karine Canani\n12-Temas contemporâneos em psicopedagogia:\n1- Inclusão e atuação do Psicopedagogo - Dra. Cristiane Souza;\n2- Uso das tecnologias e asimplicações para aprendizagem - Esp. Letícia Ruiz\n3- Altas Habilidades e Superdotação - Vera Pereira\n4- Direito Educacional Aplicado - Esp. Vladimir Miná\n5- Disciplina baseada em Virtudes -  Esp. LetíciaRuiz\n\n13 Seminário de práticas Psicopedagógicas - Ma. Fabiana Josefa Sousa/ Ma. Luciana Siqueira\n\nO valor de investimento na Pós-graduação em Psicopedagogia  está em 18 mensalidades de *R$ 479,16*. Esse mês esta com condições especiais com 50% de desconto e as mensalidades está por R$ 239,58 \n\n Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para abril/2026.","time":"23/02/2026 09:44:34","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Qual a exigência na formação?","time":"23/02/2026 10:16:05"},{"role":"agent","text":"*Karina Pimentel:* Qualquer graduação reconhecida pelo MEC!","time":"23/02/2026 10:33:33","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Sou formada em educação física","time":"23/02/2026 10:55:59"},{"role":"client","text":"Posso fazer a pós?","time":"23/02/2026 10:56:08"},{"role":"agent","text":"*Karina Pimentel:* Pode sim!\n","time":"23/02/2026 10:58:56","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"As aulas iniciam em abril, isso?","time":"23/02/2026 11:16:53"},{"role":"client","text":"Estou em dúvida se façoa pós em psicopedagogia ou psicoteologia. \nJá estou cursando a pós em educação clássica cristã e qro fazer mais uma.","time":"23/02/2026 11:18:35"},{"role":"client","text":"Você pode por gentileza, passar as disciplinas da pós em psicoteologia. Para eu comparar as duas e definir uma.","time":"23/02/2026 11:19:41"},{"role":"agent","text":"*Karina Pimentel:* Isso mesmo!","time":"23/02/2026 11:20:59","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Claro!","time":"23/02/2026 11:21:14","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* *PÓS-GRADUAÇÃO EM PSICOTEOLOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n560 horas\n\nDISCIPLINAS\n13 disciplinas \n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n******************\nDisciplinas e Professores:\n\nMódulos Psicoteologia Teórica\n\n1 Introdução à Psicoteologia - Dr. Sérgio Queiroz\n2 Introdução à Cosmovisão e Filosofia cristã - Dr. Bruno Ribeiro\n3 Fundamentos Históricos e Filosóficos da Psicoteologia - Dr. Josemar Bandeira\n4 Psicoteologia Cristã Ortodoxa - Dr. Sérgio Queiroz\n\nMódulos Psicoteologia Aplicada\n\n5 Correntes Contemporâneas das Psicoterapias - Ms. Fabiana Souza /\nDra. Rebecca Athayde\n6 Psicoterapia Tomista I – Introdução à Psicoterapia Tomista, Emoções e paixões. Dr. Andrei Alves\n7 Psicoterapia Tomista II – Psicopatologias da alma e formação da personalidade - Dr. Andrei Alves /\nMs. Daniel Ouriques\n8 Introdução a ciência da felicidade - Ms. Alessandra Magalhães\n9 Terapia Cognitivo Comportamental em Psicoteologia - Dra. Cyntia Diógenes / Ms. Alessandra Magalhães /\nEsp. Juliana Araújo\n10 Logoterapia: sentido da vida e Psicoteologia - Dr. Alisson de Meneses Pontes\n11 Neurociências, psicoterapia do trauma e fé cristã - Esp. Aender Borba / Esp. Ramon Medeiros\n12 Psicoteologia do Aconselhamento Bíblico - Dr. Saulo Ribeiro - Ms. Gabriela Rique\n\nMódulos Psicoteologia Experimental\n\n13 Metodologia da pesquisa em Psicoteologia - Ms. Raphael Falcão\n*********\nO valor de investimento na Pós-graduação em Psicoteologia será de: 16 mensalidades de R$ 487,00.\nEsse mês esta com condições especiais com 50% de desconto e as mensalidades ficam por R$ 243,50\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, *previsto para 30/03.","time":"23/02/2026 11:21:55","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Estou cursando a pós em educação clássica cristã \nTem alguma matéria que irei cursar novamente?","time":"23/02/2026 11:25:04"},{"role":"client","text":"Mesmos não tendo a graduação em pedagogia, somente com a pós em psicopedagogia vou poder ter acesso ao certificado e atuar na área?","time":"23/02/2026 11:28:48"},{"role":"agent","text":"*Karina Pimentel:* Se tiver mesma disciplina, poderá ser eliminada!","time":"23/02/2026 11:28:51","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Como faço para verificar e solicitar a eliminação?","time":"23/02/2026 11:37:22"},{"role":"agent","text":"*Karina Pimentel:* 📌 Para realizar o aproveitamento de disciplinas você enviará o Requerimento de Aproveitamento de Estudos preenchido ( https://bit.ly/Aproveitamento-FICV ), junto com o histórico e o ementário das disciplinas desejadas para o e-mail:\n\nfaculdade@cidadeviva.org\n\nCom o assunto: Aproveitamento de disciplinas.","time":"23/02/2026 11:43:53","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Mesmo não tendo a graduação em pedagogia, somente com a pós em psicopedagogia vou poder ter acesso ao certificado e atuar na área?","time":"23/02/2026 12:53:58"},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!","time":"23/02/2026 13:27:13","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Sim, somente não terás o certificado de Pós, se não tiver nenhuma graduação reconhecida pelo MEC! Nessa situação de não ter a Graduação reconhecida, receberá um certificado de curso livre!","time":"23/02/2026 13:28:17","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Arquivo | (https://igrejabatista.widechat.com.br/config/storage/view/699c81244ef9203123004ee3)","time":"23/02/2026 13:32:36"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"24/02/2026 10:39:11","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Ficou alguma duvida?","time":"24/02/2026 10:39:16","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Vamos prosseguir com a sua inscrição? ","time":"24/02/2026 10:39:26","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Bom Dia\nMinha dúvida maior está nesta questão.\nAo concluir a pós em psicopedagogia vou poder atuar na área mesmo não tendo formação em pedagogia?","time":"24/02/2026 10:58:26"},{"role":"agent","text":"*Karina Pimentel:* Sim!","time":"24/02/2026 14:31:45","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nSimone Dilda Rovani, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"25/02/2026 18:10:17"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"25/02/2026 18:10:18"},{"role":"client","text":"Simone Dilda Rovani, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"25/02/2026 18:25:19"}]$tag$, $tag$2026-02-23 08:58:07+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 14, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.c