INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$642afe9f-31e5-4905-88a3-e1c98ca25d54$tag$, $tag$2026021100366$tag$, $tag$Sales (5583920001233)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Graça e Paz de Cristo Boa  tarde.\nJá estou algum tempo querendo pagar a mensalidade do Mês da faculdade e ñ consigo. Como faço?","time":"11/02/2026 15:52:51"},{"role":"client","text":"🌟 Boa tarde Sales! Que alegria ter você aqui com a gente! 🙌","time":"11/02/2026 15:52:51"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"11/02/2026 15:52:56"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"11/02/2026 15:53:00"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"11/02/2026 15:53:05"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"11/02/2026 15:53:11"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"11/02/2026 15:53:17"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"11/02/2026 15:53:19"},{"role":"client","text":"Sim, concordo","time":"11/02/2026 15:59:54"},{"role":"client","text":"✅ Obrigado, Sales! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"11/02/2026 15:59:55"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"11/02/2026 15:59:59"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"11/02/2026 16:00:51"},{"role":"client","text":"Olá! Sales!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"11/02/2026 16:00:52"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"11/02/2026 16:00:57"},{"role":"client","text":"Falar com um atendente","time":"11/02/2026 16:01:28"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"11/02/2026 16:01:30"},{"role":"client","text":"Financeiro","time":"11/02/2026 16:01:55"},{"role":"client","text":"Estou tentando pagar a mensalidade do Mês e ñ consigo.","time":"11/02/2026 16:07:41"},{"role":"client","text":"Vi aqui um email disponibilizando o pagamento é de vocês?","time":"11/02/2026 16:12:50"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/698cd4cdf9628a94b400c48b)","time":"11/02/2026 16:13:17"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"11/02/2026 21:05:30"},{"role":"client","text":"Graça e paz de Cristo. Bom dia. Pode me ajudar?","time":"12/02/2026 10:05:23"},{"role":"client","text":"Podem me ajudar por favor?","time":"12/02/2026 10:09:08"},{"role":"client","text":"Em relação a esse pagamento?","time":"12/02/2026 10:09:21"},{"role":"client","text":"Da mensalidade do Mês de Fevereiro 2026?","time":"12/02/2026 10:09:43"},{"role":"client","text":"A página de vcs ñ estava disponível para pagamento","time":"12/02/2026 10:10:25"},{"role":"client","text":"E um e-mail me foi enviado  disponibilizando o pagamento. O email é realmente de vcs?","time":"12/02/2026 10:11:35"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/698dd1977fef6e24b20e66b0)","time":"12/02/2026 10:11:51"},{"role":"client","text":"Arquivo de vídeo | (https://igrejabatista.widechat.com.br/config/storage/view/698dd20169da1d67df0200d2)","time":"12/02/2026 10:13:38"},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!\n\nAgradecemos por ter aguardado até o momento.\n\nInformamos que estamos passando por um processo de transição de sistema e, por esse motivo, tivemos uma demanda elevada relacionada à emissão de boletos. No entanto, já estamos atuando ativamente para regularizar a situação de cada aluno de forma individual.\n\nMais uma vez, agradecemos pela sua paciência e compreensão.\n\nAinda hoje você receberá, em seu e-mail cadastrado, um link de pagamento com as opções de pagamento via Pix ou boleto. O e-mail será enviado pela Faculdade Internacional Cidade Viva, por meio da plataforma Sponte.\n\nGostaríamos de salientar que o seu desconto está mantido. Você não pagará juros nem multa.\n\nRessaltamos que, em um primeiro momento, o valor da parcela poderá aparecer de forma integral. No entanto, ao prosseguir para a etapa final do pagamento, seja na modalidade Pix ou boleto, o desconto de pontualidade será aplicado automaticamente, apresentando o valor correto para pagamento.\n\nFique tranquilo(a), pois o valor será ajustado corretamente no momento da finalização do pagamento.\n\nQualquer dúvida, estamos à disposição.\n\nMais uma vez, muito obrigado por aguardar.\nDeus abençoe.\n\nSecretaria Acadêmica\nFaculdade Internacional Cidade Viva","time":"12/02/2026 13:44:41","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nSales, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 13:44:44"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"12/02/2026 13:44:46"},{"role":"client","text":"Sales, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"12/02/2026 13:59:46"}]$tag$, $tag$2026-02-11 15:52:51+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 1, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$37dcc488-8fca-425f-8924-8e02cefd66c5$tag$, $tag$2026022300114$tag$, $tag$Augusto Campelo (5583988697197)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde me chamo Thayanne Sales da Cidade Viva! \n","time":"23/02/2026 13:45:53","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Olá boa tarde!","time":"23/02/2026 15:27:58"},{"role":"agent","text":"*Thayanne Sales:* Olá, graça e paz! 🙏\n\nMe chamo Thayanne, sou do Setor de Relacionamento da Faculdade Internacional Cidade Viva, e é um prazer falar com você! 😊\n\nIdentificamos o seu interesse por um dos nossos cursos vindo do Congresso Consciência Cristã e eu estou aqui para lhe auxiliar e tirar todas as suas dúvidas.\n\n\nQual o curso deseja informações?","time":"23/02/2026 15:31:49","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nAugusto Campelo, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"24/02/2026 15:38:48"}]$tag$, $tag$2026-02-23 13:45:53+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:42:01.563441+00$tag$, 9, 10, 5, 2, 7, 2, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, me