INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$80553760-e749-4049-b77a-59f4fd4bb7dd$tag$, $tag$2026022400037$tag$, $tag$Izabelly Gomes (5591985713643)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá, estou no sétimo semestre de direito e gostaria de saber como eu faço para me transferir, no período noturno","time":"24/02/2026 08:19:29"},{"role":"client","text":"🌟 Bom dia Izabelly Gomes! Que alegria ter você aqui com a gente! 🙌","time":"24/02/2026 08:19:31"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"24/02/2026 08:19:34"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"24/02/2026 08:19:38"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"24/02/2026 08:19:42"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"24/02/2026 08:19:48"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"24/02/2026 08:19:53"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"24/02/2026 08:19:54"},{"role":"client","text":"Sim, concordo","time":"24/02/2026 08:20:07"},{"role":"client","text":"✅ Obrigado, Izabelly Gomes! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"24/02/2026 08:20:08"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"24/02/2026 08:20:12"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"24/02/2026 08:20:25"},{"role":"client","text":"Olá! Izabelly Gomes!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"24/02/2026 08:20:26"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"24/02/2026 08:20:30"},{"role":"client","text":"Falar com um atendente","time":"24/02/2026 08:20:43"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"24/02/2026 08:20:44"},{"role":"client","text":"Olá, estou no sétimo semestre de direito e gostaria de saber como eu faço para me transferir, no período noturno","time":"24/02/2026 08:21:13"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"24/02/2026 08:25:10"},{"role":"client","text":"Olá, estou no sétimo semestre de direito e gostaria de saber como eu faço para me transferir, no período noturno","time":"24/02/2026 09:33:45"},{"role":"client","text":"Arquivo | (https://igrejabatista.widechat.com.br/config/storage/view/699d9b2750840ce1d20e0815)","time":"24/02/2026 09:35:51"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"24/02/2026 09:46:01","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar o formulário de analise das disciplinas ok!","time":"24/02/2026 09:46:16","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* È reconhecido pelo MEC?","time":"24/02/2026 09:46:29","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* 📌 Para realizar o aproveitamento de disciplinas você enviará o Requerimento de Aproveitamento de Estudos preenchido ( https://bit.ly/Aproveitamento-FICV ), junto com o histórico e o ementário das disciplinas desejadas para o e-mail:\n\nfaculdade@cidadeviva.org\n\nCom o assunto: Aproveitamento de disciplinas.","time":"24/02/2026 09:46:59","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Qual seria o valor?","time":"24/02/2026 09:48:51"},{"role":"client","text":"Da mensalidade","time":"24/02/2026 09:48:55"},{"role":"agent","text":"*Karina Pimentel:* A mensalidade da Graduação em Direito está R$ 1.407,95.\n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação!\n\nA primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖","time":"24/02/2026 09:49:31","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Bacharelado em Direito\n\nGRADUAÇÃO COM COSMOVISÃO CRISTÃ\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\nNOTA MÁXIMA NO MEC\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( bit.ly/3LlEgJS ) com duração de 5 anos.\n\nPRÁTICA JURÍDICA\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\nNÚCLEO\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\nVOCAÇÃO\nEspecialização durante a graduação com disciplinas optativas nas áreas:\n\na) Serviço Público;\nb) Advocacia Empreendedora;\nc) Academia\n\nBIBLIOTECA DIGITAL\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\nAULAS PRESENCIAIS\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.\n\nSegue a matriz curricular do curso de Direito bit.ly/3SpepqX","time":"24/02/2026 09:49:46","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!","time":"24/02/2026 16:02:22","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Ficou alguma duvida?","time":"24/02/2026 16:02:27","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Vamos prosseguir com a sua inscrição?","time":"24/02/2026 16:02:39","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Não entendi a questão da mensalidade","time":"24/02/2026 16:15:59"},{"role":"client","text":"Então a mensalidade é 1.400?","time":"24/02/2026 16:16:08"},{"role":"client","text":"Ou é esse valor + com desconto","time":"24/02/2026 16:16:20"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/699ee3eed15691f9a70f841d)","time":"25/02/2026 08:58:38","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/699ee3fc4837d6255f0104c0)","time":"25/02/2026 08:58:52","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Aí eu teria que pagar tudo? Esses 3.379?","time":"25/02/2026 09:10:43"},{"role":"client","text":"Entendi","time":"25/02/2026 09:10:59"},{"role":"client","text":"Atendimento Finalizado!\n\nIzabelly Gomes, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"26/02/2026 09:57:35"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"26/02/2026 09:57:36"},{"role":"client","text":"Izabelly Gomes, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"26/02/2026 10:12:37"}]$tag$, $tag$2026-02-24 08:19:29+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 11, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score =